{
  "pergunta": "Me de um panorama rapido do estado atual do sistema Orbis.",
  "historico": []
}

{
  "pergunta": "Me mostre os dados principais do usuario {{ _.usuario_id }}, incluindo role e se ele esta ativo.",
  "historico": []
}

{
  "pergunta": "Procure usuarios com nome {{ _.usuario_nome }} e me diga role, email e se estao ativos.",
  "historico": []
}

{
  "pergunta": "Mostre todos os tecnicos ativos do sistema.",
  "historico": []
}

{
  "pergunta": "O tecnico {{ _.tecnico_id }} esta ativo? Se puder, me diga tambem a especialidade dele e se esta com alerta em andamento.",
  "historico": []
}

{
  "pergunta": "Procure tecnicos com nome {{ _.tecnico_nome }} e me diga quais estao ativos, a especialidade e se tem alerta em andamento.",
  "historico": []
}

{
  "pergunta": "E entre esses tecnicos, qual parece mais adequado para atender um caso de vibracao?",
  "historico": [
    {
      "role": "user",
      "content": "Mostre todos os tecnicos ativos do sistema."
    },
    {
      "role": "assistant",
      "content": "Consultei os tecnicos ativos e posso te ajudar a comparar os perfis."
    }
  ]
}

{
  "pergunta": "Me traga os detalhes do sensor {{ _.sensor_id }}, incluindo tipo, status e maquina vinculada.",
  "historico": []
}

{
  "pergunta": "Procure sensores do tipo {{ _.sensor_tipo }} e me diga o status e a maquina de cada um.",
  "historico": []
}

{
  "pergunta": "Me explique o alerta {{ _.alerta_id }}, com a maquina, sensor, tecnico e eventos recentes.",
  "historico": []
}

{
  "pergunta": "Quais sao os alertas ativos mais recentes do sistema?",
  "historico": []
}

{
  "pergunta": "Quais alertas a maquina {{ _.maquina_id }} tem agora? Mostre so os ativos.",
  "historico": []
}

{
  "pergunta": "Quais alertas estao com o tecnico {{ _.tecnico_id }}? Mostre apenas os ativos.",
  "historico": []
}

{
  "pergunta": "Quero os detalhes da manutencao {{ _.manutencao_id }}, com alerta e tecnico vinculados.",
  "historico": []
}

{
  "pergunta": "Quais manutencoes estao ligadas ao alerta {{ _.alerta_id }}?",
  "historico": []
}

{
  "pergunta": "Quero detalhes da maquina {{ _.maquina_id }}. Me diga se ela esta ativa, a integridade, criticidade e setor.",
  "historico": []
}

{
  "pergunta": "Procure maquinas com nome {{ _.maquina_nome }} e me diga quais estao ativas, a integridade, criticidade e setor.",
  "historico": []
}

{
  "pergunta": "Quais sao as maquinas mais criticas agora?",
  "historico": []
}

{
  "pergunta": "Tem sensores offline recentes? Me diga o tipo e a maquina de cada um.",
  "historico": []
}

{
  "pergunta": "Quais maquinas possuem alerta ativo agora?",
  "historico": []
}
